const Q_PHYSICS_2019_MODEL_II=[{"id": "objective>Physics>2019 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Neutrons were discovered by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Faraday</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dalton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">James Chadwick</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rutherford </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Neutrons were discovered by James Chadwick in 1932. This discovery was a significant advancement in the field of nuclear physics.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ELEMENTARY STRUCTURE OF THE ATOM"}, {"id": "objective>Physics>2019 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of a nucleus is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total number of its proton & neutrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of its protons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass of its electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total number of its protons & electrons </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of a nucleus is primarily determined by the number of protons and neutrons it contains, as these particles are much heavier than electrons. Therefore, the mass of a nucleus is the total number of its protons & neutrons.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ELEMENTARY STRUCTURE OF THE ATOM"}, {"id": "objective>Physics>2019 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three resistors with resistance 200Ω, 500Ω and 1kΩ are connected in series. A 6v battery is connected to either end of the combination. Calculate the potential difference between the ends of 200Ω resistance.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.71V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.7V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.82V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019 Model II/img1.png\" style=\"position:relative;max-width:100%;\"/> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span> = 200 + 500 + 1000 = 1700Ω <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P.d</td><td style=\"text-align:center;\">(across</td><td style=\"text-align:center;\">200Ω)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />1700</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.71V</td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY : OHM’S LAW"}, {"id": "objective>Physics>2019 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An a.c of 1A at a frequency of 800 cycles per second flows through a coil, the inductance of which is 2.5mH and the resistance of which is 5Ω. What is the power absorbed in the Coil?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8W</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The power absorbed in a coil can be calculated using the formula P = I^2 * R, where I is the current and R is the resistance. Substituting the given values, we get P = (1A)^2 * 5Ω = 5W.</div>", "topic": "SIMPLE A. C. CIRCUITS : INDUCTOR - INDUCTIVE REACTANCE"}, {"id": "objective>Physics>2019 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In semi-conductor, the carriers of current at room temperature are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrons only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons and holes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">holes only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electron and ions</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a semiconductor, both electrons and holes serve as charge carriers. Electrons carry negative charge while holes carry positive charge. When an electron moves from the valence band to the conduction band, it leaves a hole behind in the valence band. This movement of electrons and holes results in the flow of current.</div>", "topic": "INTRODUCTORY ELECTRONICS"}, {"id": "objective>Physics>2019 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water and Kerosine are drawn respectively into the two limbs of a Hare's apparatus. The destiny of water is 1.0gcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> and the density of kerosine is 0.80gcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. If the height of the water column is 20.0cm, calculate the height of the kerosine column.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.6cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.0cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Devices with different liquids  <br/> d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 1 × 20 = 0.8 × h <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />0.8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25cm</td></tr></table></div></div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2019 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a girl moves towards a plane mirror at a speed of 4.0m/s, the distance between the girl & her image reduces a speed of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 m/s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">d<hr size=\"1\" />t</td><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">d</td></tr></table></div> <br/> d = x, v = 4m/s  <br/> d = 2x, v = ? (girl & image) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 × 4<hr size=\"1\" />x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8</td><td style=\"text-align:center;\">m<hr size=\"1\" />s</td></tr></table></div></div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2019 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One newton × One meter equals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">One water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">One Joule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">One ampere </div>", "<div style=\"font-family:Cambria;font-size:17px;\">One kilogram</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One newton multiplied by one meter equals one Joule. This is because Joule is the unit of work done or energy, which is defined as the product of force (in newtons) and distance (in meters).</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2019 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A microscope is focused on a mark on a table, when the mark is covered by a plate of glass 2cm thick, the microscope has to be raised 0.67cm for the mark to be once more in focus. Calculate the refractive index.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.68</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.55</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.82</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The refractive index can be calculated using the formula:  <br/> Refractive index = Thickness of the glass / (Thickness of the glass - Shift in focus).  <br/> Substituting the given values, we get Refractive index = 2 / (2 - 0.67) = 1.50.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2019 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Radio waves belongs to the class of wave whose velocity is about </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">340m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>m/s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Radio waves are a type of electromagnetic wave. The speed of all electromagnetic waves in a vacuum, including radio waves, is approximately 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span> meters per second.</div>", "topic": "ELECTROMAGNETIC SPECTRUM"}, {"id": "objective>Physics>2019 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A single force which produces the same effect as a set of forces acting together at a point is known as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">component</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equilibrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resultant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">resistant </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The resultant force is a single force that has the same effect as all the forces acting on an object. It is the vector sum of all the forces acting on an object. The other options do not correctly define this concept. A component is a part of a vector, the equilibrant is a force that brings an object to equilibrium, and resistant is a force that opposes motion.</div>", "topic": "EQUILIBRIUM OF FORCES"}, {"id": "objective>Physics>2019 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following statement about the electromagnet shown above is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">when the current flows from A to B, the end A will be in north pole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">when the current flows from A to B, the end A will be south pole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">when the current flows from A to B, the end B will not be north pole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">none of the above</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A - B = S - N. <br/> Also, starting end of the current is south while terminating end is North.</div>", "topic": "MAGNETIC FIELD : ELECTROMAGNETS"}, {"id": "objective>Physics>2019 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the velocity ratio of a screw jack of pitch 0.2cm if the length of the tommy bar is 23cm</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">230π</div>", "<div style=\"font-family:Cambria;font-size:17px;\">23π</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70π</div>", "<div style=\"font-family:Cambria;font-size:17px;\">140π</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity ratio (VR) of a screw jack is given by the formula VR = 2πL/P, where L is the length of the tommy bar and P is the pitch of the screw. Substituting the given values, we get VR = 2π*23/0.2 = 230π. Therefore, the correct answer is option 1.</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>2019 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Earth's magnetic equator passes through Jos in Nigeria. At Jos, the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">angle of variation is zero </div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetic declination is 90</div>", "<div style=\"font-family:Cambria;font-size:17px;\">angle of dip is zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizontal component at the Earth's field is zero</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- angle of dip is zero at the magnetic equator  <br/> - angle of variation is the same as angle of declination.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : EARTH’S MAGNETIC FIELD"}, {"id": "objective>Physics>2019 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car moving at 20m/s with its horn blowing (f = 1200Hz) is chasing another car going at 15m/s. What is the apparent frequency of the horn as heard by the driver being chased?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.22KHz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.40KHz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.12KHz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.22Hz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Source (horn) frequency: fs = 1200 Hz <br/> Speed of source (chasing car): vs = 20 m/s <br/> Speed of observer (car being chased): vo = 15 m/s <br/> Speed of sound in air: v = 343 m/s (assuming standard conditions) <br/>  <br/> Since both the source and observer are moving in the same direction, we use the Doppler formula for a moving source and observer: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f'</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">&#215;</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">v - v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span><hr size=\"1\" />v - v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f'</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1200</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">343 - 15<hr size=\"1\" />343 - 20</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f'</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1200</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">328<hr size=\"1\" />323</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1219</td><td style=\"text-align:center;\">Hz</td></tr></table></div> <br/> ∴ f' = 1.22 kHz <br/> </div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2019 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Any line or section taken through an advancing wave in which all the particles are in the same phase is called the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wave coast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wave trough</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wave front</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wave front is a line or section taken through an advancing wave in which the particles are in phase.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2019 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In which of the points labelled A, B, C, D and E on the conductor shown would electric charge tend to concentrate most </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Charge are mostly concentrated at the outermost part of a hollow conductor  <br/> - Charge are also mostly concentrated at the pointed ends or places with high density point.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2019 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The point at which the molecules of a loaded wire begin to slide across each other resulting in a rapid increase in extension is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yield point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">proportionality point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deformation point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">elastic point </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The yield point is the point on a stress-strain curve that indicates the limit of elastic behavior and the beginning of plastic behavior. Below this point, a material will deform elastically and will return to its original shape when the applied stress is removed. Once the yield point is passed, some fraction of the deformation will be permanent and non-reversible. Therefore, the correct answer is 'yield point'.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2019 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The resultant capacitance in the figure above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15μf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.8μf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.3μf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8μf</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For the parallel arrangement  = 2 + 4 = 6μf <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">For</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">series</td><td style=\"text-align:center;\">arrangement</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15<hr size=\"1\" />12</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.8μf</td></tr></table></div></div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2019 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The lower fixed part of a faulty thermometer reads 2°C while the upper fixed point is 100°C. <br/> What is the true temperature when the thermometer reads 51°C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">52°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">49°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">46°C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">θ</span> = 51, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 2, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">100</span> = 100 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">θ</span> - C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">100</span> - C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">51 - 2<hr size=\"1\" />100 - 2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">49<hr size=\"1\" />98</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> θ =50°C.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2019 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a body moves with a constant speed and at the same time undergoes an acceleration, its motion is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">circular </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oscillatory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rectilinear </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotational</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a body moves with a constant speed and at the same time undergoes an acceleration, its motion is said to be circular </div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2019 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A coil X is moved quickly away from the end Y of a stationary metal bar and a current then flows in X as shown above. <br/> Then </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the bar is not a magnet </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y is a north pole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y is a South pole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y repels coil X</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">N - S magnet is moved towards a coil production clockwise direction of current in the coil. <br/> - This is the same as a coil moved away from S-N (Y - North pole)</div>", "topic": "ELECTROMAGNETIC INDUCTION"}, {"id": "objective>Physics>2019 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boy pushes a 500kg box along a floor with a force of 2000N. If the velocity of the box is uniform, the co-efficient of friction between the box and the floor is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.65</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">m = 500kg, W = mg = 500 × 10 = 5000N <br/> F = 2000N <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">μ</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Force at constant velocity<hr size=\"1\" />weight</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2000<hr size=\"1\" />5000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.4</td></tr></table></div></div>", "topic": "FRICTION"}, {"id": "objective>Physics>2019 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are some units  <br/> I. Ns <br/> II. Non <br/> III. Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> IV. JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> V. JKg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> What is the unit of latent heat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unit of latent heat is Joules per kilogram (J/kg). From the given options, the correct unit is JKg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> which is represented as V in the question.</div>", "topic": "CHANGE OF STATE : LATENT HEAT"}, {"id": "objective>Physics>2019 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When two objects A and B are supplied with the same quantity of heat, the temperature change in A is obtained to be twice that of B. The mass of A is half that of B. The ratio of the specific heat capacity of A to B is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 : 4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 : 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 : 1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 2θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>,  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td></tr></table></div> <br/> H = MCθ <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>c<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>c<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> <br/> ( 1/2 m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> )C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> (2θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>) = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>c<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />1</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> ⇒ 1 : 1 <br/> </div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2019 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of 0.354g of helium at 273°C and 114cm of mercury pressure is 2667cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>. Calculate the new volume at stp.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1896.07cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200.025cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1967.27cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2000.25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">m = 0.354g, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 273°C = 273 + 273 = 546K <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 114cmHg, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2667cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at STP <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 273K, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 76cmHg, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">114 × 2667 × 273<hr size=\"1\" />76 × 546</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2000.25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div></div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2019 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the molecular explanation, heat is transferred by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">free electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">free atoms </div>", "<div style=\"font-family:Cambria;font-size:17px;\">free molecules </div>", "<div style=\"font-family:Cambria;font-size:17px;\">free solids </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the molecular explanation, heat is transferred by the free molecules. This is because heat transfer at the molecular level is primarily due to the movement of molecules and the interaction between them. When a molecule is heated, it starts to move and vibrate faster. These molecules then bump into nearby molecules, transferring some of their energy. This process continues and propagates through the material, resulting in heat transfer.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2019 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is observed when air is pumped out of a discharge tube without lowering its pressure </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the conductivity of the air increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the conductivity of the air decreases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduction does not occur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">spark are produced </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Conduction takes places in gases when air is pumped out of a discharged tube under reduced pressure.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2019 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following characteristics of a wave is used in the measurement of the depth of the Sea?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffraction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">interference </div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristic of a wave used in the measurement of the depth of the Sea is reflection. This is done using a technique called sonar (Sound Navigation and Ranging). In sonar, a sound wave is emitted, which travels through the water, hits the sea floor, and reflects back. The time it takes for the wave to return is measured and used to calculate the depth of the sea.</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2019 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the attraction of the sun is suddenly ceased, the earth would continue to move in a straight line making a tangent with the original orbit. This statement is derived from Newton's</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">First law of motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Second law of motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Third law of motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Law of universal gravitation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement is derived from Newton's First Law of Motion. This law, also known as the Law of Inertia, states that an object at rest stays at rest and an object in motion stays in motion with the same speed and in the same direction unless acted upon by an unbalanced force. If the sun's attraction (which is the centripetal force that keeps the earth in its orbit) suddenly ceased, there would be no force to deviate the earth from its straight-line path, hence it would continue to move in a straight line tangent to its original orbit.</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2019 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Heat may be transferred by conduction, convention and radiation. By which of these methods does heat travel through vacuum?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Conduction only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convection only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radiation only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">All these methods</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat can be transferred by conduction, convection, and radiation. However, only radiation can transfer heat through a vacuum. Conduction and convection require a medium (solid, liquid, or gas) to transfer heat, while radiation transfers heat in the form of electromagnetic waves and doesn't require a medium.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2019 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the human eye that does similar work as the diaphragm of a camera lens is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ciliary muscles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pupil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iris </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Retina </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iris is similar to diaphragm both help regulate the amountof light rays entering.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2019 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A projectile of mass 4kg is fired vertically and reaches a maximum height of 40m. Calculate the potential energy at the highest point <br/> (g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1800J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1600J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">440J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The potential energy (PE) at the highest point of a projectile can be calculated using the formula PE = mgh, where m is the mass, g is the acceleration due to gravity, and h is the height. Substituting the given values, we get PE = 4kg * 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> * 40m = 1600J. Therefore, the correct answer is 1600J.</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2019 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The length of the seconds hand of laboratory clock is 0.1m. Calculate the speed at the top of the seconds hand </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.05 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.85 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.50 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.25 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Length of the seconds hand = r = 0.1m but the seconds hand rotates through 360° or 2π rad in 60s. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Thus,</td><td style=\"text-align:center;\">ω</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />60</td></tr></table></div> <br/> Velocity of the tip of the hand, V = ωr <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />60</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2π<hr size=\"1\" />600</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">π<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.142<hr size=\"1\" />300</td></tr></table></div> <br/> V = 0.01047 = 1.05 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2019 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Workdone on an object to bring it to a certain point in space is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gravitational potential energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potential energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mechanical energy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gravitational potential energy is the energy an object possesses because of its position in a gravitational field. Since the force required to lift it is equal to its weight, it follows that the gravitational potential energy is equal to its weight times the height to which it is lifted. (i.e, P.E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = ωh, where ω = mg)</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2019 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A copper rod, 5m long when heated through 10C, expands by 1mm. If a second copper rod, 2.5m long is heated through 5c, by how much will it expand?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.125mm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 5m, ΔT = 10c, l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1mm <br/> l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2.5m, ΔT = 5c, l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">using</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>ΔT</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />5(10)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2.5(5)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.5(5)<hr size=\"1\" />5(10)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.25mm</td></tr></table></div></div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2019 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A safety precaution designed to prolong the life of a lead acid accumulator is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">By topping up the cells with concentrated acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The use of naked flame when charging the battery </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Keeping the specific gravity of the electrolyte within specified range </div>", "<div style=\"font-family:Cambria;font-size:17px;\">By connecting wires to the terminals directly when testing the level of charging</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Topping is done with distilled water <br/> - Naked flame should be avoided when charging the battery <br/> - Direct connection of wires to the terminals should be avoided.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2019 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of water vapour in a given volume of air is 0.05g at 20°C, while the mass of water vapour required to saturate it at the same temperature is 0.15g. Calculate the relative humidity of the air.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.33%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.55%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.33%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">55.55%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">RH</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass of water vapour in volume of air<hr size=\"1\" />mass of water vapour for saturation</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">RH</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<hr size=\"1\" />M</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.05<hr size=\"1\" />0.15</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />0.15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">33.33%</td></tr></table></div></div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2019 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The angular dispersion of a prism depends on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The index of refraction only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The angle of incidence as well as the index of refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The angle of incidence only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The thickness of the prism only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dispersion is due to different refractive indices speeds and wavelengths.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2019 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements are correct of the production and propagation of waves? <br/> I. vibration produces waves <br/> II. waves transmit energy along the medium <br/> III. the medium through which the wave travels does not travel with the wave  <br/> IV. waves do not require any medium for transmission</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I & IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II & IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III & IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Waves are produced by vibration <br/> - Waves transmit energy along the medium <br/> - Particles of a medium vibrate with the wave motion without the entire medium <br/> - Some waves require medium for transmission (mechanical).</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2019 Model II>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rectangular solid block has length 10cm, breadth 5cm and height 2cm. If it lies on a horizontal surface, and has density 100kg/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, calculate the pressure it exerts on the surface.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mg<hr size=\"1\" />A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(ρ × v) × g<hr size=\"1\" />A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ρ × (A × h) × g<hr size=\"1\" />A</td></tr></table></div> <br/> P = 100 × 2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> × 10 = 20 N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "topic": "PRESSURE"}, {"id": "objective>Physics>2019 Model II>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram shows four positions of the bob of a simple pendulum. At which of these positions does the bob have maximum kinetic energy and minimum potential energy </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bob have maximum kinetic energy and minimum potential energy at the point 2.</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2019 Model II>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is acted upon by a system of parallel three causing the object to be in state equilibrium. Which of the following statement is not correct</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the resultant of the parallel forces is zero </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the algebraic sum of all the moments of the forces is zero </div>", "<div style=\"font-family:Cambria;font-size:17px;\">all the parallel forces must be equal in magnitude and direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the sum of forces in one direction must be equal to the sum of forces in the opposite direction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement 'all the parallel forces must be equal in magnitude and direction' is not correct. In a state of equilibrium, the resultant of the parallel forces is zero and the algebraic sum of all the moments of the forces is zero. However, this does not mean that all the parallel forces must be equal in magnitude and direction. The forces only need to balance each other out, they do not need to be equal.</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2019 Model II>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is/are correct for a freely falling body? <br/> I. the total is entirely kinetic <br/> II. the ratio of potential energy to kinetic energy is constant  <br/> III. the sum of potential and kinetic energy is constant</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- the total energy at any point is a combination of the P.E and K.E <br/> - the sum of PE and KE at any point is always constant not the ratio of P.E to K.E</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2019 Model II>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Efficiency of conduction in liquids and gases compared to solids is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less efficient than solid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">more efficient than solids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equally efficient to solids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">efficiently may vary</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The efficiency of conduction in liquids and gases is less efficient than in solids. This is because solids have closely packed particles which allows for easy transfer of heat energy from one particle to another, while in liquids and gases, the particles are more spread out, making the transfer of heat energy less efficient.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES~~CONDUCTION OF ELECTRICITY THROUGH : LIQUIDS"}, {"id": "objective>Physics>2019 Model II>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A well 1km deep is filled with a liquid of density 950kg/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and g = 10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, the pressure at the bottom of the well is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P = Pa + ρgh = (1.00 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>) + (950 × 10 × 1000) <br/> P = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> + (95 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>) = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>(1 + 95) = 96 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> <br/> P = 9.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> N/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE~~PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2019 Model II>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"Sum of all forces acting on a body is zero.\" This condition represents equilibrium' </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">First condition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Second condition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Third condition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fourth condition</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement 'Sum of all forces acting on a body is zero' represents the first condition of equilibrium. In physics, the first condition of equilibrium states that the vector sum of all forces acting on an object must be zero for the object to be in equilibrium. This is a direct consequence of Newton's first law of motion.</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2019 Model II>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following bodies, each with centre of gravity G, lying on a horizontal table, is/are in unstable equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II & III only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- I & II are in neutral equilibrium. They will roll continuously on the table <br/> - III is a body with high centre of gravity (unstable) <br/> - IV is a body with high centre of gravity (stable)</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2019 Model II>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of a stone having an irregular shape can be determined using?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">meter rule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">measuring cylinder </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vernier calliper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">micrometer screw gauge </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of object is the same as the volume of liquid displaced in a container such as measuring cylinder.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2019 Model II>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Sunlight, a blue flower looks blue because we see the flower by the light it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">receives from our eyes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disperses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">absorbed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflect </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When we see a blue flower, it appears blue because it absorbs all colors of light except blue. It reflects blue light, which reaches our eyes and causes us to perceive the flower as blue. This is a fundamental concept in optics known as color reflection.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2019 Model II>51", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a projectile has a maximum range of 40m. Find its speed of projection  <br/> (g = 10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 m/s</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum range of a projectile is given by the formula R = (v^2)/g, where v is the speed of projection and g is the acceleration due to gravity. Rearranging the formula to solve for v gives v = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">R*g&nbsp;</span>. Substituting the given values R = 40m and g = 10m/s^2 gives v = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">40*10&nbsp;</span> = 20 m/s.</div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2019 Model II>52", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the same interval, it is observed that a train travels the same distance as does a lorry. The two vehicles therefore have the same </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Uniform acceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Instantaneous velocity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Initial velocity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Average speed </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a train and a lorry travel the same distance in the same interval of time, they have the same average speed. Average speed is defined as the total distance traveled divided by the total time taken. It does not mean they have the same acceleration, instantaneous velocity, or initial velocity, as these factors can vary while still achieving the same average speed.</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2019 Model II>53", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following media would the average speed of the molecule of water be highest?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water - Steam</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Average speed of molecules increases in order: Solid - liquid - gases thus, gas vapour or steam has the highest average speed.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2019 Model II>54", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The power source of a ticker - timer vibrates 40 times in one seconds. If the ticker - timer made 200 dot during an experiment, determine how long the experiment lasted </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">25s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">45s </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5s</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">t<hr size=\"1\" />n</td></tr></table></div> <br/> Tn = t <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />40</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">200</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5s</td></tr></table></div></div>", "topic": "MEASUREMENTS AND UNITS : TIME"}, {"id": "objective>Physics>2019 Model II>55", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object immersed in fluid experiences an upward force named </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">viscocity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drag force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">upthrust </div>", "<div style=\"font-family:Cambria;font-size:17px;\">friction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A fluid will exert a force upward on a body if it is partly or wholly submerged within it. This is because the deeper into a fluid you go, the greater the weight of it and so the greater the pressure. This difference in pressure between the top and the bottom of the object produces an upward force on it.  <br/> This is called Upthrust.</div>", "topic": "LIQUIDS AT REST : UPTHRUST"}, {"id": "objective>Physics>2019 Model II>56", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boat travels due east at a speed of 40m/s across a river flowing due south at 30m/s.  <br/> What is the resultant speed of the boat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.3 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.0 m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70.0 m/s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019 Model II/img8.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  <br/> R = 50m/s <br/>  <br/> ∴ the resultant speed of the boat is 50m/s.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2019 Model II>57", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dimension of pressure is equivalent to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure is defined as force per unit area. The dimension of force is MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> and that of area is L^2. Therefore, the dimension of pressure is ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.</div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2019 Model II>58", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of physical quantities comprises vectors?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capacitance and inductance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">force ratio and velocity ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">friction and momentum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy and power</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- capacitance and inductance are scalar  <br/> - free ratio (MA) & velocity are scalar  <br/> - energy & power are scalar</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2019 Model II>59", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The direction of the path taken by light is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Locus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Line </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ray</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beam</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Ray is the direction or path taken by light energy <br/> - a beam is a stream of light energy or collection of many rays.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2019 Model II>60", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is exclusive property of a transverse waves?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Compression</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Polarization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Only transverse waves exhibit polarization i.e vibration along a perpendicular direction to the direction of travel of wave.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2019 Model II>61", "question": "<div style=\"font-family:Cambria;font-size:17px;\">118.8cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> surface area of the copper cathode of a voltmeter is to be coated with 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m thick copper of density 9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. How long will the process run with 10A constant current. <br/> ( ece of copper = 3.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>kgc<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.8mins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0mins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.4mins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.0mins</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Volume = Area × thickness <br/> ⇒ 118.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Mass = Density × Volume  <br/> ⇒ 118.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> × 9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> ⇒ 1069.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>kg <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<hr size=\"1\" />ZI</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1069.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span><hr size=\"1\" />3.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> × 10</td></tr></table></div> <br/> t = 324s <br/> ⇒ 5.4mins</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2019 Model II>62", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Large metal bridges are often mounted on roller bearings in order to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent the bridges from sinking into the ground </div>", "<div style=\"font-family:Cambria;font-size:17px;\">support the weight of the bridges </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent the bridges from changing their lengths </div>", "<div style=\"font-family:Cambria;font-size:17px;\">allow for expansion and contraction of the bridges</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Large metal bridges are often mounted on roller bearings to allow for expansion and contraction of the bridges. This is because metal expands when it is heated and contracts when it is cooled. If the bridges were rigidly fixed, the expansion and contraction could cause the bridges to crack or buckle. By allowing the bridges to move slightly, the roller bearings prevent this damage.</div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2019 Model II>63", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To satisfy first condition of equilibrium, if rightward force are positive, leftward forces must be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">positive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative </div>", "<div style=\"font-family:Cambria;font-size:17px;\">doubled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">halved </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first condition of equilibrium states that the sum of all forces acting on an object must be zero. If rightward forces are considered positive, then leftward forces must be considered negative to satisfy this condition. This is because forces in opposite directions have opposite signs.</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}];
